import React from 'react';

const WeatherCard = ({
  city,
  icon,
  temperature,
  feelsLike,
  condition,
  wind,
  humidity,
  aqi
}) => {
  
  // Helper to determine AQI text/color based on the US EPA Index (1-6)
  const getAQIDesc = (index) => {
    const levels = {
      1: { text: "Good", color: "#4caf50" },
      2: { text: "Moderate", color: "#ffeb3b" },
      3: { text: "Unhealthy for Sensitive Groups", color: "#ff9800" },
      4: { text: "Unhealthy", color: "#f44336" },
      5: { text: "Very Unhealthy", color: "#9c27b0" },
      6: { text: "Hazardous", color: "#7e0023" }
    };
    return levels[index] || { text: "Unknown", color: "#999" };
  };

  const aqiInfo = getAQIDesc(aqi);

  return (
    <div className="card">
      <div className="card-header">
        <h2>{city}</h2>
        <p className="condition-text">{condition}</p>
      </div>

      <div className="weather-main">
        {/* Added a check to ensure icon exists */}
        {icon && <img src={icon} alt={condition} className="weather-icon" />}
        <div className="temp-display">
          <span className="current-temp">{Math.round(temperature)}°C</span>
        </div>
      </div>

      <div className="stats-grid">
        <div className="stat-box">
          <span className="stat-label">Feels Like</span>
          <span className="stat-value">🌡️ {Math.round(feelsLike)}°C</span>
        </div>
        <div className="stat-box">
          <span className="stat-label">Wind Speed</span>
          <span className="stat-value">💨 {wind} km/h</span>
        </div>
        <div className="stat-box">
          <span className="stat-label">Humidity</span>
          <span className="stat-value">💧 {humidity}%</span>
        </div>
      </div>

      {aqi && (
        <div 
          className="aqi-badge" 
          style={{ borderLeft: `4px solid ${aqiInfo.color}` }}
        >
          <span className="aqi-label">Air Quality Index: </span>
          <span className="aqi-value">{aqi} - {aqiInfo.text}</span>
        </div>
      )}
    </div>
  );
};

export default WeatherCard;
